// ── Laufzeit: übersetzt alle Textknoten + Platzhalter, beobachtet DOM-Änderungen ──
(function(){
  var lang=localStorage.getItem('rv-lang')||'de';
  document.documentElement.lang=lang;
  if(lang==='de')return; // Quellsprache
  var idx=window.I18N_ORDER.indexOf(lang); if(idx<0)return;
  var CAT={leicht:null,mittel:null,schwer:null};
  function lookup(key){
    var e=window.I18N_SRC[key]; if(e&&e[idx])return e[idx];
    for(var i=0;i<window.I18N_PATTERNS.length;i++){
      var p=window.I18N_PATTERNS[i]; if(!p[1])continue;
      var m=key.match(p[0]); if(!m)continue;
      var t=p[1][idx]; if(!t)return null;
      for(var g=1;g<m.length;g++)t=t.split('$'+g).join(m[g]);
      return t;
    }
    // Kategorie-Chip: "leicht · 1,5 Pkt/Set"
    var cm=key.match(/^(leicht|mittel|schwer) · ([\d.,]+)\s*$/);
    if(cm){var c=window.I18N_SRC[cm[1]];if(c&&c[idx])return c[idx]+' · '+cm[2];}
    return null;
  }
  function trNode(n){
    var s=n.nodeValue; if(!s)return;
    var key=s.trim(); if(!key||key.length<2)return;
    var out=lookup(key);
    if(out!=null&&out!==key)n.nodeValue=s.replace(key,out);
  }
  function walk(node){
    if(node.nodeType===3){trNode(node);return;}
    if(node.nodeType!==1)return;
    var tag=node.tagName; if(tag==='SCRIPT'||tag==='STYLE')return;
    if(node.placeholder){var p=lookup(node.placeholder.trim()); if(p)node.placeholder=p;}
    for(var c=node.firstChild;c;c=c.nextSibling)walk(c);
  }
  function start(){
    walk(document.body);
    new MutationObserver(function(muts){
      for(var i=0;i<muts.length;i++){
        var m=muts[i];
        if(m.type==='characterData')trNode(m.target);
        else for(var j=0;j<m.addedNodes.length;j++)walk(m.addedNodes[j]);
      }
    }).observe(document.body,{childList:true,subtree:true,characterData:true});
  }
  // Start verzögern, bis das gesamte Skript (inkl. Nachträge) geparst ist
  setTimeout(function(){ if(document.body)start(); else document.addEventListener('DOMContentLoaded',start); },0);
})();
